176	  it.todo("rune damage 200 G yields payout 100 G");
177	
178	  // Deductible per damage event
179	  it.todo("dragon attack damaging sword (500 G) and amulet (300 G) yields payout 600 G");
180	
181	  // High enchantment threshold
